<?php declare(strict_types=1); namespace App\Http\Controllers\Payroll; use App\Http\Controllers\Controller; use App\Http\Requests\Payroll\GeneratePayrollRunRequest; use App\Models\Employee; use App\Models\Payroll\PayrollPeriod; use App\Models\Payroll\PayrollRun; use App\Services\Payroll\PayrollCalculationService; use Illuminate\Http\RedirectResponse; use Illuminate\View\View; class PayrollRunController extends Controller{public function index():View{return view('payroll.runs.index',['title'=>'Proses Payroll','runs'=>PayrollRun::with('period')->latest()->paginate(15)]);} public function generate(PayrollPeriod $period):View{return view('payroll.runs.generate',['title'=>'Generate Payroll','period'=>$period,'employees'=>Employee::where('is_active',true)->get()]);} public function store(GeneratePayrollRunRequest $r,PayrollPeriod $period,PayrollCalculationService $s):RedirectResponse{$run=$s->generate($period,$r->input('employee_ids',[]),$r->user()->id);return redirect()->route('payroll.runs.preview',$run)->with('status','Payroll berhasil dihitung dan siap dipreview.');} public function preview(PayrollRun $run):View{return view('payroll.runs.preview',['title'=>'Preview Payroll','run'=>$run->load('period','items.components')]);} public function show(PayrollRun $run):View{return view('payroll.runs.show',['title'=>'Detail Payroll Run','run'=>$run->load('period','items')]);} public function item(\App\Models\Payroll\PayrollItem $item):View{return view('payroll.runs.item',['title'=>'Detail Payroll Pegawai','item'=>$item->load('run.period','components','payments')]);}}
